Rules.InvariantScript:
Set(
    gblTextClickedSaveScreen,
    Blank()
);
UpdateContext(
    {
        locLeadTestPerformed: !IsBlank(
            LookUp(
                colCdsWindowMeasurements,
                Job.Job = gblRecordJobCurrent.Job And (!IsBlank('Lead Test: Exterior Component') Or !IsBlank('Lead Test: Interior Component'))
            )
        ),
        locShowConfirmFinishJob: false
    }
);

// Unblock user input
UpdateContext({locShowConfirmFinishJob: false});
Reset(tog_FinalSteps_SendEmail);

// Block user input
UpdateContext({locBlockUserInput: true});
// Go to save screen and save only the current job
Set(
    gblRecordJobCurrent,
    Patch(
        colCdsJobs,
        LookUp(
            colCdsJobs,
            appJobIDText = gblRecordJobCurrent.appJobIDText
        ),
        {
            Completed: gblOptionSets.Job.CompletedJob.Yes,
            'Job Finished: Send Email?': gblOptionSets.Job.JobFinishedSendEmail.Yes,
            'Job Package: Send Documents?': gblOptionSets.Job.JobPackageSendDocuments.Yes,
            'Lead Test: Send Document?': If(
                tog_FinalSteps_SendEmail.Value,
                gblOptionSets.Job.LeadTestSendDocuments.Yes,
                gblOptionSets.Job.LeadTestSendDocuments.No
            )
        }
    )
);
With(
    {
        varType: "colCdsJobs",
        varRecordRef: gblRecordJobCurrent.Job
    },
    If(
        IsBlank(
            LookUp(
                colAUDRecords,
                Type = varType
                And RecordRef = varRecordRef
            )
        ),
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "U"
            }
        )
    )
);
Set(gblTextClickedSaveScreen, "Jobs Screen");
Navigate(
    'Saving Screen',
    ScreenTransition.Fade,
    {
        locSaveText: "Saving job to Vesta Data"
    }
);
UpdateContext({locBlockUserInput: false});

Set(
    gblRecordJobCurrent,
    Patch(
        colCdsJobs,
        LookUp(
            colCdsJobs,
            appJobIDText = gblRecordJobCurrent.appJobIDText
        ),
        {
            Completed: gblOptionSets.Job.CompletedJob.No,
            'Lead Test: Send Document?': If(
                tog_FinalSteps_SendEmail.Value,
                gblOptionSets.Job.LeadTestSendDocuments.Yes,
                gblOptionSets.Job.LeadTestSendDocuments.No
            )
        }
    )
);
Set(gblTextClickedSaveScreen, "Final Steps Screen");
Navigate(
    'Saving Screen',
    ScreenTransition.Fade,
    {locSaveText: "Saving data to Vesta Data..."}
)

With(
    {
        varElevationCount: CountRows(
            Filter(
                colCdsJobPhotos,
                colCdsJobPhotos[@Job].Job = gblRecordJobCurrent.Job,
                Type in [
                    gblOptionSets.Global.PhotoType.ElevationFront,
                    gblOptionSets.Global.PhotoType.ElevationRear,
                    gblOptionSets.Global.PhotoType.ElevationSide
                ]
            )
        )
    },
    Navigate(
        'Photos Screen',
        ScreenTransition.None,
        {
            locModeElevation: true,
            locModeDefault: false,
            locModeWindow: false,
            locShowTypes: varElevationCount = 0,
            locShowPhotos: varElevationCount > 0,
            locAddPhotoLabel: "",
            locReturnScreen: 'Final Steps Screen'
        }
    )
)

Table(
    {
        Item: "Rooms",
        Message: With(
            {
                varWindowsNotCompleted: CountRows(
                    Filter(
                        colCdsWindowMeasurements,
                        Job.Job = gblRecordJobCurrent.Job,
                        Completed = gblOptionSets.WindowMeasurement.Completed.No,
                        Type = gblOptionSets.WindowMeasurement.Type.Tech,
                        Status <> gblOptionSets.WindowMeasurement.Status.Inactive
                    )
                )
            },
            If(
                varWindowsNotCompleted > 0,
                Text(
                    varWindowsNotCompleted,
                    "[$-en-US]0"
                ) & " windows have not been completed for this job",
                "Completed"
            )
        ),
        Success: CountRows(
            Filter(
                colCdsWindowMeasurements,
                Job.Job = gblRecordJobCurrent.Job,
                Completed = gblOptionSets.WindowMeasurement.Completed.No,
                Type = gblOptionSets.WindowMeasurement.Type.Tech,
                Status <> gblOptionSets.WindowMeasurement.Status.Inactive
            )
        ) = 0
    },
    {
        Item: "Labor",
        Message: If(
            IsEmpty(
                Filter(
                    colCdsJobLaborItems,
                    appJobIDText = gblRecordJobCurrent.appJobIDText,
                        Status <> gblOptionSets.JobLaborItem.Status.Inactive
                )
            ),
            "No labor items were found for this job",
            CountRows(
                Filter(
                    colCdsJobLaborItems,
                    appJobIDText = gblRecordJobCurrent.appJobIDText,
                    IsBlank(Quantity),
                    Status <> gblOptionSets.JobLaborItem.Status.Inactive
                )
            ) > 0,
            Text(
                CountRows(
                    Filter(
                        colCdsJobLaborItems,
                        appJobIDText = gblRecordJobCurrent.appJobIDText,
                        IsBlank(Quantity),
                        Status <> gblOptionSets.JobLaborItem.Status.Inactive
                    )
                ),
                "[$-en-US]0"
            ) & " labor item(s) are missing quantity information",
            "Completed"
        ),
        Success: With(
            {
                tblJobLaborItems: Filter(
                    colCdsJobLaborItems,
                    appJobIDText = gblRecordJobCurrent.appJobIDText,
                    Status <> gblOptionSets.JobLaborItem.Status.Inactive
                )
            },
            !IsEmpty(tblJobLaborItems) And IsEmpty(
                Filter(
                    tblJobLaborItems,
                    IsBlank(Quantity)
                )
            )
        )
    },
    {
        Item: "Materials",
        Message: If(
            IsEmpty(
                Filter(
                    colCdsJobMaterialItems,
                    appJobIDText = gblRecordJobCurrent.appJobIDText,
                    Status <> gblOptionSets.JobMaterialItem.Status.Inactive
                )
            ),
            "No materials items were found for this job",
            CountRows(
                Filter(
                    colCdsJobMaterialItems,
                    appJobIDText = gblRecordJobCurrent.appJobIDText,
                    IsBlank(Quantity) Or IsBlank(Color),
                    Status <> gblOptionSets.JobMaterialItem.Status.Inactive
                )
            ) > 0,
            Text(
                CountRows(
                    Filter(
                        colCdsJobMaterialItems,
                        appJobIDText = gblRecordJobCurrent.appJobIDText,
                        IsBlank(Quantity) Or IsBlank(Color),
                        Status <> gblOptionSets.JobMaterialItem.Status.Inactive
                    )
                ),
                "[$-en-US]0"
            ) & " materials item(s) are missing quantity or color information",
            "Completed"
        ),
        Success: With(
            {
                tblJobMaterialItems: Filter(
                    colCdsJobMaterialItems,
                    appJobIDText = gblRecordJobCurrent.appJobIDText,
                    Status <> gblOptionSets.JobMaterialItem.Status.Inactive
                )
            },
            !IsEmpty(tblJobMaterialItems) And IsEmpty(
                Filter(
                    tblJobMaterialItems,
                    IsBlank(Quantity) Or IsBlank(Color),
                    Status <> gblOptionSets.JobMaterialItem.Status.Inactive
                )
            )
        )
    },
    {
        Item: "Elevation Photos",
        Message: With(
            {
                tblJobPhotos: Filter(
                    colCdsJobPhotos,
                    colCdsJobPhotos[@Job].Job = gblRecordJobCurrent.Job,
                    Status <> gblOptionSets.JobPhoto.Status.Inactive
                )
            },
            If(
                IsBlank(
                    LookUp(
                        tblJobPhotos,
                        Type = gblOptionSets.Global.PhotoType.ElevationFront
                        And Status <> gblOptionSets.JobPhoto.Status.Inactive
                    )
                ) Or IsBlank(
                    LookUp(
                        tblJobPhotos,
                        Type = gblOptionSets.Global.PhotoType.ElevationSide
                        And Status <> gblOptionSets.JobPhoto.Status.Inactive
                    )
                ) Or IsBlank(
                    LookUp(
                        tblJobPhotos,
                        Type = gblOptionSets.Global.PhotoType.ElevationRear
                        And Status <> gblOptionSets.JobPhoto.Status.Inactive
                    )
                ),
                With(
                    {
                        varMessagePhoto: "Missing elevation photos: " & If(
                            IsBlank(
                                LookUp(
                                    tblJobPhotos,
                                    Type = gblOptionSets.Global.PhotoType.ElevationFront
                        And Status <> gblOptionSets.JobPhoto.Status.Inactive
                                )
                            ),
                            "front, "
                        ) & If(
                            IsBlank(
                                LookUp(
                                    tblJobPhotos,
                                    Type = gblOptionSets.Global.PhotoType.ElevationSide
                        And Status <> gblOptionSets.JobPhoto.Status.Inactive
                                )
                            ),
                            "side, "
                        ) & If(
                            IsBlank(
                                LookUp(
                                    tblJobPhotos,
                                    Type = gblOptionSets.Global.PhotoType.ElevationRear
                                    And Status <> gblOptionSets.JobPhoto.Status.Inactive
                                )
                            ),
                            "rear, "
                        )
                    },
                    Left(
                        varMessagePhoto,
                        Len(varMessagePhoto) - 2
                    )
                ),
                "Completed"
            )
        ),
        Success: With(
            {
                tblJobPhotos: Filter(
                    colCdsJobPhotos,
                    colCdsJobPhotos[@Job].Job = gblRecordJobCurrent.Job,
                    Status <> gblOptionSets.JobPhoto.Status.Inactive
                )
            },
            !IsBlank(
                LookUp(
                    tblJobPhotos,
                    Type = gblOptionSets.Global.PhotoType.ElevationFront
                    And Status <> gblOptionSets.JobPhoto.Status.Inactive
                )
            ) And !IsBlank(
                LookUp(
                    tblJobPhotos,
                    Type = gblOptionSets.Global.PhotoType.ElevationSide
                    And Status <> gblOptionSets.JobPhoto.Status.Inactive
                )
            ) And !IsBlank(
                LookUp(
                    tblJobPhotos,
                    Type = gblOptionSets.Global.PhotoType.ElevationRear
                    And Status <> gblOptionSets.JobPhoto.Status.Inactive
                )
            )
        )
    },
    {
        Item: "Documents",
        Message: With(
            {
                varJobDocsNotCompleted: CountRows(
                    Filter(
                        colCdsJobDocuments,
                        appJobIdText = gblRecordJobCurrent.appJobIDText,
                        Completed = gblOptionSets.JobDocument.Completed.No
                    )
                )
            },
            If(
                varJobDocsNotCompleted > 0,
                varJobDocsNotCompleted & " required document(s) have not been signed for this job",
                "Completed"
            )
        ),
        Success: With(
            {
                varJobDocsNotCompleted: CountRows(
                    Filter(
                        colCdsJobDocuments,
                        appJobIdText = gblRecordJobCurrent.appJobIDText,
                        Completed = gblOptionSets.JobDocument.Completed.No
                    )
                )
            },
            varJobDocsNotCompleted = 0
        )
    },
    {
        Item: "Overview",
        Message: With({varCountNotes: CountRows(Filter([!IsBlank(gblRecordJobCurrent.'Overview: Style Of Home'),!IsBlank(gblRecordJobCurrent.'Overview: Construction'),!IsBlank(gblRecordJobCurrent.'Overview: Exterior Covering'),!IsBlank(gblRecordJobCurrent.'Overview: Exterior Capping'),!IsBlank(gblRecordJobCurrent.'Overview: Existing Windows'),!IsBlank(gblRecordJobCurrent.'Overview: Special Equipment Needed'),!IsBlank(gblRecordJobCurrent.'Overview: Special Conditions'),!IsBlank(gblRecordJobCurrent.'Overview: Notes')], !Value))}, If(varCountNotes>0, varCountNotes&" note(s) have not been filled in", "Completed")),
        Success: !IsBlank(gblRecordJobCurrent.'Overview: Style Of Home') And !IsBlank(gblRecordJobCurrent.'Overview: Construction') And !IsBlank(gblRecordJobCurrent.'Overview: Exterior Covering') And !IsBlank(gblRecordJobCurrent.'Overview: Exterior Capping') And !IsBlank(gblRecordJobCurrent.'Overview: Existing Windows') And !IsBlank(gblRecordJobCurrent.'Overview: Special Equipment Needed') And !IsBlank(gblRecordJobCurrent.'Overview: Special Conditions') And !IsBlank(gblRecordJobCurrent.'Overview: Notes')
    }
)
